WORD  bfReserved1;   WORD  bfReserved2;   DWORD bfOffBits;
} BITMAPFILEHEADER, *LPBITMAPFILEHEADER, *PBITMAPFILEHEADER;
成员 bfType
文件类型;必须 0x4d42  (ASCII 字符串“BM”) 。 bfSize
位图文件的大小（以字节为单位）。 bfReserved1
保留;必须为零。 bfReserved2
保留;必须为零。 bfOffBits
